module.exports = { simulateSwap };

/**
 * @param {{ web3: any; userAddress: string; inToken: string; outToken: string; inAmount: string; swapTarget: string; swapApprovalTarget: string; swapCallData: string; recipient: string; }} params
 */
async function simulateSwap(params) {
  let { web3, userAddress, inToken, outToken, inAmount, swapTarget, swapApprovalTarget, swapCallData, recipient } =
    params;
  swapApprovalTarget = swapApprovalTarget || swapTarget;
  recipient = recipient || userAddress;

  const mc = "0x0000000000000000000000000000000000001234";

  try {
    web3.eth.extend({
      methods: [
        {
          name: "callWithState",
          call: "eth_call",
          params: 3,
        },
      ],
    });

    const calls = [
      balanceOf(web3, mc, outToken, recipient),
      transfer(web3, mc, inToken, userAddress, inAmount),
      approve(web3, mc, inToken, swapApprovalTarget, inAmount),
      {
        target: swapTarget,
        callData: swapCallData,
      },
      transfer(web3, mc, outToken, recipient, inAmount),
      balanceOf(web3, mc, outToken, recipient),
    ];

    const result = await web3.eth.callWithState(
      {
        to: userAddress,
        data: web3.eth.abi.encodeFunctionCall(multicallAggregateAbi, [calls]),
      },
      "latest",
      {
        [userAddress]: { code: multicallBytecode },
        [mc]: { code: multicallBytecode },
        [recipient]: { code: multicallBytecode },
      }
    );

    const results = web3.eth.abi.decodeParameters(multicallAggregateAbi.outputs, result)[1];

    const startBalance = web3.eth.abi.decodeParameters([{ name: "outBalance", type: "uint256" }], results[0])[0];

    const endBalance = web3.eth.abi.decodeParameters(
      [{ name: "outBalance", type: "uint256" }],
      results[calls.length - 1]
    )[0];

    const outAmount = BigInt(endBalance) - BigInt(startBalance);
    if (outAmount <= 0) throw new Error("invalid output amount");

    return { success: true, outAmount: outAmount.toString(), gasCost: "0" };
  } catch (e) {
    return { success: false, error: e.message, outAmount: "0", gasCost: "0" };
  }
}

const approve = (web3, mc, token, spender, amount) => ({
  target: token,
  callData: web3.eth.abi.encodeFunctionCall(
    {
      name: "approve",
      type: "function",
      inputs: [
        {
          type: "address",
          name: "spender",
        },
        {
          type: "uint256",
          name: "amount",
        },
      ],
    },
    [spender, amount]
  ),
});

const transferFrom = (web3, mc, token, sender, recipient, amount) => ({
  target: token,
  callData: web3.eth.abi.encodeFunctionCall(
    {
      name: "transferFrom",
      type: "function",
      inputs: [
        {
          type: "address",
          name: "sender",
        },
        {
          type: "address",
          name: "recipient",
        },
        {
          type: "uint256",
          name: "amount",
        },
      ],
    },
    [sender, recipient, amount]
  ),
});

const transfer = (web3, mc, token, recipient, amount) => ({
  target: token,
  callData: web3.eth.abi.encodeFunctionCall(
    {
      name: "transfer",
      type: "function",
      inputs: [
        {
          type: "address",
          name: "recipient",
        },
        {
          type: "uint256",
          name: "amount",
        },
      ],
    },
    [recipient, amount]
  ),
});

const balanceOf = (web3, mc, token, target) =>
  isNativeAddress(token)
    ? {
        target: mc,
        callData: web3.eth.abi.encodeFunctionCall(
          {
            name: "getEthBalance",
            type: "function",
            inputs: [
              {
                type: "address",
                name: "account",
              },
            ],
          },
          [target]
        ),
      }
    : {
        target: token,
        callData: web3.eth.abi.encodeFunctionCall(
          {
            name: "balanceOf",
            type: "function",
            inputs: [
              {
                type: "address",
                name: "account",
              },
            ],
          },
          [target]
        ),
      };

const nativeTokenAddresses = [
  "0x0000000000000000000000000000000000000000",
  "0x0000000000000000000000000000000000001010",
  "0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE",
  "0x000000000000000000000000000000000000dEaD",
  "0x000000000000000000000000000000000000800A",
];

const isNativeAddress = (address) =>
  !!nativeTokenAddresses.find((a) => a == address || a.toLowerCase() === address.toLowerCase());

const multicallAggregateAbi = {
  constant: false,
  inputs: [
    {
      components: [
        { name: "target", type: "address" },
        { name: "callData", type: "bytes" },
      ],
      name: "calls",
      type: "tuple[]",
    },
  ],
  name: "aggregate",
  outputs: [
    { name: "blockNumber", type: "uint256" },
    { name: "returnData", type: "bytes[]" },
  ],
  payable: false,
  stateMutability: "nonpayable",
  type: "function",
};

// custom multicall supporting fallback and receive functions
const multicallBytecode =
  "";
